'use client'
import { FileCard } from './_components/file-card'
import FilesPageDTO from 'api/src/dto/files-page-dto'

export default async function MainPage() {

  const response: Response = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/files/`);
  const filesPage: FilesPageDTO = await response.json();


  return (
    <html>
      <body>
        <h1>Список загруженных файлов</h1>
        <ul>
          {filesPage?.items.map((val, ind, ar) => (
            <li key={val.id}>
              <FileCard metadata={val} />
            </li>
          ))}
        </ul>
      </body>
    </html>
  );
}